local StructFarmLand = LXImport("..Struct.StructFarmLand")
local StructSimplePlayerInfo = LXImport("..Struct.StructSimplePlayerInfo")
---@class StructFarm
local StructFarm = LxClass("StructFarm", nil)


function StructFarm:StructFarm()
    -- 活动id
    self.activityId       = 0;
    -- 目标角色id
    self.playerId         = 0;
    --玩家信息
    ---@type StructSimplePlayerInfo
    self.roleInof = nil
    -- 地块信息
    ---@type table<number,StructFarmLand>
    self.lands      = {};
    -- 巡逻结束时间,秒
    self.patrolDogTime    = 0;
    -- 免费增加种子时间,秒
    ---@type table<number,number>
    self.seedRecoverTime = {}
    -- 待收取偷菜失败掉落积分
    self.dropScore        = 0;
    -- 今日已偷取次数
    self.stealingNum      = 0;
    --是否有空土地
    self.hasNilLand = false
end

function StructFarm:CreateByPb(pb)
    self.activityId       = pb.activityId;
    -- 目标角色id
    self.playerId         = pb.target;
    -- 地块信息
    ---@type table<StructFarmLand>
    self.lands      = {};
    local num = 0
    for _, value in ipairs(pb.lands) do
        self:OnUpdateFarmLand(value)
        num = num+1
    end
    self.hasNilLand = num<ModelFarm.MaxLandNum
    -- 巡逻结束时间,秒
    self.patrolDogTime    = pb.patrolDogTime or 0;
    -- 免费增加种子时间,秒
    for _, value in ipairs(pb.recovers) do
        self.seedRecoverTime[value.seed] = value.recoverTime
    end
    -- 待收取偷菜失败掉落积分
    self.dropScore        = pb.dropScore;
    -- 今日已偷取次数
    self.stealingNum      = pb.stealingNum;
    self.roleInfo = StructSimplePlayerInfo:New()
    self.roleInfo:CreateByPb(pb.playerInfo)
end

function StructFarm:OnUpdateFarmLand(pb)
	---@type StructFarmLand
	local farmInfo = self.lands[pb.index]
	if not farmInfo then farmInfo = StructFarmLand:New() end
	farmInfo:CreateByPb(pb)
	self.lands[pb.index] = farmInfo
end

return StructFarm